export const v7FlowboardVersion = "V7.1";

const withReview = (config) => ({
  ...config,
  owner: config.owner ?? "PM / Design / Eng",
  phase: config.phase ?? "MVP",
  priority: config.priority ?? (config.structure === "safety" || config.structure === "blocking" ? "P0" : config.structure === "error" ? "P1" : "P2"),
  apiContract: config.apiContract ?? config.dev?.[0] ?? "frontend-state",
  analyticsKey: config.analyticsKey ?? `taotao_v71_${config.id}`,
  dependencies: config.dependencies ?? ["auth", "conversation-state"],
  review: {
    user: `主视角看到「${config.phone?.title ?? config.title}」，动作必须明确可点。`,
    partner: config.actor.includes("双方") || config.actor.includes("阿川") || config.actor.includes("任一方")
      ? "另一方视角必须有对应状态或同步说明。"
      : "无另一方打扰。",
    recovery: config.structure === "error" ? "必须可退出、重试或回到上一状态。" : "失败时保留输入和上下文。",
    acceptance: `可验证：${config.next}`,
    ...(config.review ?? {}),
  },
});

