export function getV7FlowboardStats() {
  const states = v7FlowboardLanes.flatMap((lane) => lane.states);
  const structureCountByType = states.reduce((acc, state) => {
    acc[state.structure] = (acc[state.structure] ?? 0) + 1;
    return acc;
  }, {});
  return {
    laneCount: v7FlowboardLanes.length,
    stateCount: states.length,
    unstructuredCount: states.filter((state) => state.structure === "none").length,
    structuredCount: states.filter((state) => state.structure !== "none").length,
    structureCountByType,
  };
}
